import React, { useContext, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { X } from 'lucide-react';
import { AppCtx } from '../App';
import { fetchRuns, fetchRun } from '../api/azure';
import PageHeader from '../components/PageHeader';
import AssetIcon from '../components/AssetIcon';
import { SeverityBadge } from '../components/FindingBadges';
import {
  LoadingState, SubscriptionRequired, EmptyState, QueryErrorState,
} from '../components/QueryStates';
import { AzureResourceIcon } from '../components/FinOpsIcons';
import { PAGE_ICONS, iconFromResourceId, iconForCategory } from '../config/assetIcons';
import { formatCurrency, formatDateTime } from '../utils/format';

export default function RunHistory() {
  const { subscription } = useContext(AppCtx);
  const [selected, setSelected] = useState(null);
  const [detailId, setDetailId] = useState(null);

  const { data: runs = [], isLoading, isError, error, refetch } = useQuery({
    queryKey: ['runs', subscription],
    queryFn: () => fetchRuns({ subscription_id: subscription, limit: 50 }),
    enabled: !!subscription,
  });

  const { data: detail, isLoading: detailLoading, isError: detailError } = useQuery({
    queryKey: ['run-detail', detailId],
    queryFn: () => fetchRun(detailId),
    enabled: !!detailId,
  });

  const handleOpen = (run) => { setSelected(run); setDetailId(run.id); };

  return (
    <div>
      <PageHeader
        title="Run history"
        iconKey={PAGE_ICONS.history}
        subtitle={
          subscription
            ? `${runs.length} analysis runs · click a row to inspect all findings`
            : 'Select a subscription to view run history'
        }
      />

      {!subscription && <SubscriptionRequired />}

      {subscription && isLoading && <LoadingState message="Loading run history…" />}
      {subscription && isError && <QueryErrorState error={error} onRetry={refetch} />}
      {subscription && !isLoading && !isError && runs.length === 0 && (
        <EmptyState iconKey={PAGE_ICONS.history} message="No runs yet. Use the Dashboard to trigger an analysis." />
      )}

      {subscription && !isLoading && !isError && runs.length > 0 && (
        <div className="card">
          <div className="table-wrap">
            <table>
              <thead><tr><th>Date</th><th>Subscription</th><th>Engine</th><th>Profile</th><th>Findings</th><th>Critical</th><th>High</th><th>Est. savings/mo</th></tr></thead>
              <tbody>
                {runs.map((r) => (
                  <tr key={r.id} style={{ cursor: 'pointer' }} onClick={() => handleOpen(r)}>
                    <td style={{ color: 'var(--text)', fontWeight: 500, whiteSpace: 'nowrap' }}>
                      <span className="icon-inline">
                        <AssetIcon iconKey={PAGE_ICONS.costs} size={16} />
                        {formatDateTime(r.analyzed_at)}
                      </span>
                    </td>
                    <td style={{ fontSize: '0.78rem', maxWidth: 180, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      <span className="icon-inline">
                        <AssetIcon iconKey={PAGE_ICONS.subscription} size={14} />
                        {r.subscription_id}
                      </span>
                    </td>
                    <td><span className="badge badge-medium">{r.engine_version || 'standard'}</span></td>
                    <td><span className="badge badge-info">{r.profile || 'default'}</span></td>
                    <td style={{ fontWeight: 600 }}>{r.total_findings}</td>
                    <td><span style={{ color: 'var(--danger)', fontWeight: 700 }}>{r.critical_count || 0}</span></td>
                    <td><span style={{ color: '#fca5a5', fontWeight: 700 }}>{r.high_count || 0}</span></td>
                    <td style={{ color: 'var(--success)', fontWeight: 700 }}>
                      {formatCurrency(r.total_savings_usd || 0, { decimals: 0 })}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {selected && (
        <div className="modal-overlay" onClick={() => setSelected(null)} role="presentation">
          <div
            className="modal"
            style={{ maxWidth: '90vw', width: 900 }}
            role="dialog"
            aria-modal="true"
            onClick={(e) => e.stopPropagation()}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.25rem' }}>
              <div className="modal-title icon-inline">
                <AssetIcon iconKey={PAGE_ICONS.history} size={20} />
                Run: {formatDateTime(selected.analyzed_at)}
              </div>
              <button type="button" className="btn btn-ghost btn-icon-only" onClick={() => setSelected(null)} aria-label="Close">
                <X size={16} />
              </button>
            </div>
            {detailLoading && <LoadingState message="Loading run details…" />}
            {detailError && <QueryErrorState error={detailError} title="Failed to load run details" />}
            {detail && (
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Severity</th><th>Rule</th><th>Resource</th><th>Savings</th><th>Priority</th><th>Confidence</th><th>Score</th></tr></thead>
                  <tbody>
                    {(detail.findings || []).map((f) => (
                      <tr key={f.id || `${f.rule_id}-${f.resource_id}`}>
                        <td><SeverityBadge severity={f.severity} size={11} /></td>
                        <td style={{ color: 'var(--text)', fontWeight: 500, fontSize: '0.83rem' }}>{f.rule_name}</td>
                        <td style={{ maxWidth: 200, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', fontSize: '0.8rem' }}>
                          <span className="icon-inline">
                            <AzureResourceIcon
                              type={null}
                              src={iconFromResourceId(f.resource_id) || iconForCategory(f.category)}
                              size={16}
                            />
                            {f.resource_name || f.resource_id?.split('/').pop()}
                          </span>
                        </td>
                        <td style={{ color: f.estimated_savings_usd > 0 ? 'var(--success)' : 'var(--text3)', fontWeight: 600 }}>
                          {f.estimated_savings_usd > 0
                            ? formatCurrency(f.estimated_savings_usd, { decimals: 0 })
                            : '\u2014'}
                        </td>
                        <td>{f.action_priority || '\u2014'}</td>
                        <td>{f.confidence_score ? `${f.confidence_score}%` : '\u2014'}</td>
                        <td>{f.waste_score}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
